// CLX Lead Scoring v2 — Parse Scoring Response
//
// Apollo bonus layering (Part B.5):
//   +10 if apollo_enriched_at is set (any verified Apollo data at all)
//   +15 if job_title_verified matches the insurance_broker decision-maker
//        keywords (mirror of niche_overlays.apollo_title_keywords)
// Bonus is clamped so the total lead_score never exceeds 100.

const response = $input.item.json;
const lead = $('Split In Batches').first().json;

const rawText = (response && response.content && response.content[0] && response.content[0].text) || '';

let scoring;
try {
  const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  scoring = JSON.parse(cleaned);
} catch (e) {
  scoring = {
    lead_score: 0,
    priority_level: 'Low',
    decision_maker_probability: 'Low',
    company_size_estimate: 'SMB',
    scoring_reason: 'Manual review needed — AI parse error: ' + e.message
  };
}

// ── Apollo enrichment bonus (layered on top of Claude's base score) ──
const APOLLO_KEYWORDS = [
  'broker of record', 'principal', 'owner',
  'managing partner', 'president', 'founder'
];
const verifiedTitle = String(lead.job_title_verified || '').toLowerCase();
let apolloBonus = 0;
if (lead.apollo_enriched_at) apolloBonus += 10;
if (verifiedTitle && APOLLO_KEYWORDS.some(k => verifiedTitle.includes(k))) {
  apolloBonus += 15;
}

const baseScore = typeof scoring.lead_score === 'number' ? scoring.lead_score : 0;
const finalScore = Math.min(100, baseScore + apolloBonus);

const reasonSuffix = apolloBonus > 0
  ? ' [Apollo bonus +' + apolloBonus + ']'
  : '';

const now = new Date().toISOString();

return {
  json: {
    id: lead.id,
    lead_score: finalScore,
    priority_level: scoring.priority_level || 'Low',
    decision_maker_probability: scoring.decision_maker_probability || 'Low',
    company_size_estimate: scoring.company_size_estimate || 'SMB',
    scoring_reason: (scoring.scoring_reason || '') + reasonSuffix,
    lead_status: 'Scored',
    updated_at: now
  }
};

// CLX Lead Scoring v2 — Prep Update Score

const item = $input.item.json;

const body = {
  p_lead_id: item.id,
  p_fields: {
    lead_score: item.lead_score,
    priority_level: item.priority_level,
    decision_maker_probability: item.decision_maker_probability,
    company_size_estimate: item.company_size_estimate,
    scoring_reason: item.scoring_reason,
    lead_status: 'Scored'
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: body.p_fields.lead_status, score: item.lead_score }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
